    26→export function SourceForm({ initial, onSubmit, title, redirectTo, onSuccess, onCancel }: SourceFormProps) {
    27→  const router = useRouter();
    28→  const [saving, setSaving] = useState(false);
    29→  const [error, setError] = useState("");
    30→  const [provider, setProvider] = useState(initial?.provider ?? "dockerhub");
    31→  const [repository, setRepository] = useState(initial?.repository ?? "");
    32→  const [pollInterval, setPollInterval] = useState(String(initial?.poll_interval_seconds ?? 86400));
    33→  const [enabled, setEnabled] = useState(initial?.enabled ?? true);
    34→  const [configJson, setConfigJson] = useState(
    35→    JSON.stringify(initial?.config ?? {}, null, 2)
    36→  );
    37→  const [versionFilterInclude, setVersionFilterInclude] = useState(initial?.version_filter_include ?? "");
    38→  const [versionFilterExclude, setVersionFilterExclude] = useState(initial?.version_filter_exclude ?? "");
    39→
    40→  const handleSubmit = async (e: React.FormEvent) => {
    41→    e.preventDefault();
    42→    setError("");
    43→
    44→    const repoError = validateRepository(provider, repository);
    45→    if (repoError) {
    46→      setError(repoError);
    47→      return;
    48→    }
    49→
    50→    let parsedConfig: Record<string, unknown> | undefined;
    51→    if (configJson.trim() && configJson.trim() !== "{}") {
    52→      try {
    53→        parsedConfig = JSON.parse(configJson);
    54→      } catch {
    55→        setError("Config must be valid JSON");
    56→        return;
    57→      }
    58→    }
    59→
    60→    setSaving(true);
    61→    try {
    62→      await onSubmit({
    63→        provider,
    64→        repository: repository.trim(),
    65→        poll_interval_seconds: Number(pollInterval),
    66→        enabled,
    67→        config: parsedConfig,
    68→        version_filter_include: versionFilterInclude.trim() || undefined,
    69→        version_filter_exclude: versionFilterExclude.trim() || undefined,
    70→      });
    71→      if (onSuccess) {
    72→        onSuccess();
    73→      } else {
    74→        router.push(redirectTo ?? "/sources");
    75→      }
    76→    } catch (err: unknown) {
    77→      setError(err instanceof Error ? err.message : "Failed to save");
    78→    } finally {
    79→      setSaving(false);
    80→    }
    81→  };
    82→
    83→  const handleCancel = () => {
    84→    if (onCancel) {
    85→      onCancel();
    86→    } else {
    87→      router.back();
