    91→  const formContent = (
    92→    <form onSubmit={handleSubmit} className="space-y-4">
    93→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    94→      <div className="space-y-2">
    95→        <Label>Provider</Label>
