    97→          <SelectTrigger><SelectValue /></SelectTrigger>
    98→          <SelectContent>
    99→            <SelectItem value="dockerhub">Docker Hub</SelectItem>
   100→            <SelectItem value="github">GitHub</SelectItem>
   101→            <SelectItem value="ecr-public">ECR Public</SelectItem>
   102→          </SelectContent>
   103→        </Select>
   104→      </div>
   105→      <div className="space-y-2">
   106→        <Label htmlFor="repository">Repository</Label>
   107→        <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder="e.g. library/golang or ethereum/go-ethereum" required />
   108→      </div>
   109→      <div className="space-y-2">
   110→        <Label htmlFor="poll_interval">Poll Interval (seconds)</Label>
   111→        <Input id="poll_interval" type="number" min={60} value={pollInterval} onChange={(e) => setPollInterval(e.target.value)} />
   112→      </div>
   113→      <div className="space-y-2">
   114→        <Label htmlFor="config">Config (JSON, optional)</Label>
   115→        <Textarea
   116→          id="config"
   117→          value={configJson}
   118→          onChange={(e) => setConfigJson(e.target.value)}
   119→          rows={4}
   120→          className="font-mono text-sm"
   121→          placeholder="{}"
   122→        />
   123→      </div>
   124→      <div className="space-y-2">
   125→        <Label htmlFor="version_filter_include">Version Filter — Include (regex, optional)</Label>
   126→        <Input
   127→          id="version_filter_include"
   128→          value={versionFilterInclude}
   129→          onChange={(e) => setVersionFilterInclude(e.target.value)}
   130→          placeholder='e.g. ^v\d+\.\d+\.\d+$'
   131→          className="font-mono text-sm"
   132→        />
   133→        <p className="text-xs text-muted-foreground">Only show/notify versions matching this pattern</p>
   134→      </div>
   135→      <div className="space-y-2">
   136→        <Label htmlFor="version_filter_exclude">Version Filter — Exclude (regex, optional)</Label>
   137→        <Input
   138→          id="version_filter_exclude"
   139→          value={versionFilterExclude}
   140→          onChange={(e) => setVersionFilterExclude(e.target.value)}
   141→          placeholder='e.g. -(alpha|beta|rc|nightly)'
   142→          className="font-mono text-sm"
   143→        />
   144→        <p className="text-xs text-muted-foreground">Hide/suppress versions matching this pattern</p>
   145→      </div>
   146→      <div className="flex items-center gap-3">
   147→        <Switch checked={enabled} onCheckedChange={setEnabled} />
   148→        <Label>Enabled</Label>
   149→      </div>
   150→      <div className="flex justify-end gap-2">
   151→        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
   152→        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   153→      </div>
   154→    </form>
   155→  );
   156→
   157→  if (onSuccess) {
   158→    return formContent;
   159→  }
   160→
   161→  return (
   162→    <Card className="mx-auto max-w-2xl">
   163→      <CardHeader><CardTitle>{title}</CardTitle></CardHeader>
   164→      <CardContent>
   165→        {formContent}
   166→      </CardContent>
   167→    </Card>
   168→  );
   169→}
