   370→func (s *PgStore) CreateSubscriptionBatch(ctx context.Context, subs []models.Subscription) ([]models.Subscription, error) {
   371→	tx, err := s.pool.Begin(ctx)
   372→	if err != nil {
   373→		return nil, fmt.Errorf("begin tx: %w", err)
   374→	}
   375→	defer tx.Rollback(ctx)
   376→
   377→	var result []models.Subscription
   378→	for i := range subs {
   379→		sub := subs[i]
   380→		err := tx.QueryRow(ctx,
   381→			`INSERT INTO subscriptions (channel_id, type, source_id, project_id, version_filter)
   382→			 VALUES ($1, $2, $3, $4, $5)
   383→			 RETURNING id, created_at`,
   384→			sub.ChannelID, sub.Type, sub.SourceID, sub.ProjectID, sub.VersionFilter,
   385→		).Scan(&sub.ID, &sub.CreatedAt)
   386→		if err != nil {
   387→			return nil, fmt.Errorf("insert subscription %d: %w", i, err)
   388→		}
   389→		result = append(result, sub)
   390→	}
   391→
   392→	if err := tx.Commit(ctx); err != nil {
   393→		return nil, fmt.Errorf("commit tx: %w", err)
   394→	}
   395→	return result, nil
   396→}
