   736→	err := s.pool.QueryRow(ctx,
   737→		`SELECT id, project_id, semantic_release_id, trigger, COALESCE(version,''), status,
   738→		        COALESCE(prompt_used,''), COALESCE(error,''),
   739→		        started_at, completed_at, created_at
   740→		 FROM agent_runs WHERE id = $1`, id,
   741→	).Scan(&run.ID, &run.ProjectID, &run.SemanticReleaseID, &run.Trigger, &run.Version, &run.Status,
   742→		&run.PromptUsed, &run.Error, &run.StartedAt, &run.CompletedAt, &run.CreatedAt)
