   773→// GetPreviousRelease returns the most recent release for a source that is not
   774→// the given version, ordered by created_at descending. Returns nil (no error)
   775→// if no previous release exists.
   776→func (s *PgStore) GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error) {
   777→	var rel models.Release
   778→	err := s.pool.QueryRow(ctx,
   779→		`SELECT id, source_id, version, COALESCE(raw_data,'{}'), released_at, created_at
   780→		 FROM releases
   781→		 WHERE source_id = $1 AND version != $2
   782→		 ORDER BY COALESCE(released_at, created_at) DESC
   783→		 LIMIT 1`, sourceID, beforeVersion,
