   974→func (s *PgStore) GetTrend(ctx context.Context, granularity string, start, end time.Time) ([]TrendBucket, error) {
   975→	// Validate granularity to one of three literal values (no injection risk).
   976→	var trunc string
   977→	switch granularity {
   978→	case "daily":
   979→		trunc = "day"
   980→	case "weekly":
   981→		trunc = "week"
   982→	case "monthly":
   983→		trunc = "month"
   984→	default:
   985→		return nil, fmt.Errorf("invalid granularity: %s", granularity)
   986→	}
   987→
   988→	query := fmt.Sprintf(`
   989→		WITH buckets AS (
   990→			SELECT date_trunc('%s', gs)::date AS period
   991→			FROM generate_series($1::timestamptz, $2::timestamptz, '1 %s'::interval) gs
   992→		)
   993→		SELECT
   994→			b.period,
   995→			COALESCE(r.cnt, 0) AS releases,
   996→			COALESCE(sr.cnt, 0) AS semantic_releases
   997→		FROM buckets b
   998→		LEFT JOIN (
   999→			SELECT date_trunc('%s', COALESCE(released_at, created_at))::date AS period,
  1000→			       COUNT(*) AS cnt
  1001→			FROM releases
  1002→			WHERE COALESCE(released_at, created_at) >= $1 AND COALESCE(released_at, created_at) < $2
  1003→			GROUP BY 1
  1004→		) r ON r.period = b.period
  1005→		LEFT JOIN (
  1006→			SELECT date_trunc('%s', created_at)::date AS period,
  1007→			       COUNT(*) AS cnt
  1008→			FROM semantic_releases
  1009→			WHERE created_at >= $1 AND created_at < $2
  1010→			GROUP BY 1
  1011→		) sr ON sr.period = b.period
  1012→		ORDER BY b.period
  1013→	`, trunc, trunc, trunc, trunc)
  1014→
  1015→	rows, err := s.pool.Query(ctx, query, start, end)
  1016→	if err != nil {
  1017→		return nil, fmt.Errorf("get trend: %w", err)
  1018→	}
  1019→	defer rows.Close()
  1020→
  1021→	var buckets []TrendBucket
  1022→	for rows.Next() {
  1023→		var b TrendBucket
  1024→		var period time.Time
  1025→		if err := rows.Scan(&period, &b.Releases, &b.SemanticReleases); err != nil {
  1026→			return nil, fmt.Errorf("scan trend bucket: %w", err)
  1027→		}
  1028→		b.Period = period.Format("2006-01-02")
  1029→		buckets = append(buckets, b)
  1030→	}
  1031→	if buckets == nil {
  1032→		buckets = []TrendBucket{}
  1033→	}
  1034→	return buckets, nil
  1035→}
