    74→// Work processes a notify job: fetches the release, resolves subscriptions,
    75→// sends notifications to all matching channels, and checks agent rules to
    76→// auto-trigger agent runs when version criteria are met.
    77→func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
    78→	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
    79→	if err != nil {
    80→		return fmt.Errorf("get release: %w", err)
    81→	}
    82→
    83→	// Check source version filters — skip entirely if filtered out.
    84→	source, err := w.store.GetSource(ctx, job.Args.SourceID)
    85→	if err != nil {
    86→		return fmt.Errorf("get source: %w", err)
    87→	}
    88→	if !VersionPassesFilter(release.Version, source.VersionFilterInclude, source.VersionFilterExclude) {
    89→		slog.Debug("release filtered by version filter", "version", release.Version, "source_id", job.Args.SourceID)
    90→		return nil
    91→	}
    92→
    93→	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
    94→	if err != nil {
    95→		return fmt.Errorf("list subscriptions: %w", err)
    96→	}
    97→
    98→	for _, sub := range subs {
    99→		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
   100→		if err != nil {
   101→			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
   102→			continue
   103→		}
   104→
   105→		sender, ok := w.senders[ch.Type]
   106→		if !ok {
   107→			slog.Warn("unknown channel type", "type", ch.Type)
   108→			continue
   109→		}
   110→
   111→		msg := Notification{
   112→			Title:   fmt.Sprintf("New release: %s", release.Version),
   113→			Body:    string(release.RawData),
   114→			Version: release.Version,
   115→		}
   116→
   117→		if err := sender.Send(ctx, ch, msg); err != nil {
   118→			slog.Error("send notification failed", "channel", ch.Name, "err", err)
   119→		}
   120→	}
   121→
   122→	// Check agent rules and auto-trigger if criteria are met.
   123→	w.checkAgentRules(ctx, release, source)
   124→
   125→	return nil
   126→}
   127→
   128→// checkAgentRules evaluates the project's agent rules against the new release
   129→// and the previous release for this source. If any rule matches, an agent run
   130→// is enqueued. Errors are logged but do not fail the job — notification delivery
   131→// is the primary responsibility.
   132→func (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, source *models.Source) {
   133→	project, err := w.store.GetProject(ctx, source.ProjectID)
   134→	if err != nil {
   135→		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
   136→		return
   137→	}
   138→
   139→	// Parse the project's agent_rules JSON.
   140→	var rules models.AgentRules
   141→	if len(project.AgentRules) > 0 {
   142→		if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
   143→			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
   144→			return
   145→		}
   146→	}
   147→
   148→	// Determine the previous version for comparison.
   149→	var previousVersion string
   150→	prev, err := w.store.GetPreviousRelease(ctx, source.ID, release.Version)
   151→	if err != nil {
   152→		slog.Error("get previous release for agent rules", "source_id", source.ID, "err", err)
   153→		return
   154→	}
   155→	if prev != nil {
   156→		previousVersion = prev.Version
   157→	}
   158→
   159→	if CheckAgentRules(&rules, release.Version, previousVersion) {
   160→		trigger := fmt.Sprintf("auto:version:%s", release.Version)
   161→		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger, release.Version); err != nil {
   162→			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
   163→		} else {
   164→			slog.Info("agent run triggered by version rules",
   165→				"project_id", source.ProjectID,
   166→				"version", release.Version,
   167→				"previous_version", previousVersion,
   168→			)
   169→		}
   170→	}
   171→}
