   386→		if err != nil {
   387→			return nil, fmt.Errorf("insert subscription %d: %w", i, err)
   388→		}
   389→		result = append(result, sub)
   390→	}
   391→
   392→	if err := tx.Commit(ctx); err != nil {
   393→		return nil, fmt.Errorf("commit tx: %w", err)
   394→	}
   395→	return result, nil
   396→}
