   794→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   795→// This follows the transactional outbox pattern for zero-loss guarantee.
   796→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error {
   797→	tx, err := s.pool.Begin(ctx)
   798→	if err != nil {
   799→		return fmt.Errorf("begin tx: %w", err)
   800→	}
   801→	defer tx.Rollback(ctx)
   802→
   803→	var runID string
   804→	err = tx.QueryRow(ctx,
   805→		`INSERT INTO agent_runs (project_id, trigger, version, status)
   806→		 VALUES ($1, $2, $3, 'pending')
   807→		 RETURNING id`, projectID, trigger, version,
   808→	).Scan(&runID)
   809→	if err != nil {
   810→		return fmt.Errorf("insert agent run: %w", err)
   811→	}
   812→
   813→	if s.river != nil {
   814→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   815→			AgentRunID: runID,
   816→			ProjectID:  projectID,
   817→			Version:    version,
   818→		}, nil)
   819→		if err != nil {
   820→			return fmt.Errorf("enqueue agent job: %w", err)
   821→		}
   822→	}
   823→
   824→	return tx.Commit(ctx)
   825→}
   826→
   827→// --- OrchestratorStore (agent layer) ---
   828→
   829→// UpdateAgentRunStatus sets the status of an agent run and updates the
   830→// started_at timestamp when transitioning to "running".
   831→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   832→	var query string
   833→	switch status {
   834→	case "running":
   835→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   836→	case "completed":
   837→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   838→	default:
   839→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   840→	}
   841→	tag, err := s.pool.Exec(ctx, query, status, id)
   842→	if err != nil {
   843→		return fmt.Errorf("update agent run status: %w", err)
   844→	}
   845→	if tag.RowsAffected() == 0 {
   846→		return fmt.Errorf("agent run not found: %s", id)
   847→	}
   848→	return nil
   849→}
   850→
   851→// CreateSemanticRelease inserts a semantic release and its source release links
   852→// in a single transaction. The sr.ID field is populated on success.
   853→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   854→	tx, err := s.pool.Begin(ctx)
   855→	if err != nil {
   856→		return fmt.Errorf("begin tx: %w", err)
   857→	}
   858→	defer tx.Rollback(ctx)
   859→
   860→	err = tx.QueryRow(ctx,
   861→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   862→		 VALUES ($1, $2, $3, $4, $5)
   863→		 RETURNING id, created_at`,
   864→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   865→	).Scan(&sr.ID, &sr.CreatedAt)
   866→	if err != nil {
   867→		return fmt.Errorf("insert semantic release: %w", err)
   868→	}
   869→
   870→	for _, relID := range releaseIDs {
   871→		_, err = tx.Exec(ctx,
   872→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   873→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   874→			sr.ID, relID,
   875→		)
   876→		if err != nil {
   877→			return fmt.Errorf("insert semantic release source: %w", err)
   878→		}
   879→	}
   880→
   881→	return tx.Commit(ctx)
   882→}
   883→
   884→// UpdateAgentRunResult sets the semantic_release_id for a completed agent run.
   885→func (s *PgStore) UpdateAgentRunResult(ctx context.Context, id string, semanticReleaseID string) error {
   886→	tag, err := s.pool.Exec(ctx,
