   965→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM releases WHERE COALESCE(released_at, created_at) >= NOW() - INTERVAL '7 days'`).Scan(&stats.ReleasesThisWeek); err != nil {
   966→		return nil, fmt.Errorf("count releases this week: %w", err)
   967→	}
   968→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM semantic_releases WHERE status = 'completed' AND report->>'urgency' IN ('critical', 'high', 'CRITICAL', 'HIGH')`).Scan(&stats.AttentionNeeded); err != nil {
   969→		return nil, fmt.Errorf("count attention needed: %w", err)
   970→	}
