	defer tx.Rollback(ctx)

	var result []models.Subscription
	for i := range subs {
		sub := subs[i]
		err := tx.QueryRow(ctx,
			`INSERT INTO subscriptions (channel_id, type, source_id, project_id, version_filter)
			 VALUES ($1, $2, $3, $4, $5)
